import cn from 'clsx'
import { Link } from 'gatsby'
import React from 'react'
import type { LinkProps } from './types'
import { linkPropTypes } from './types'

/**
 * Render an internal link.
 */
export function InternalLink(props: LinkProps): React.ReactElement {
  const { children, className, url, title, ...htmlProps } = props

  return (
    <Link
      {...htmlProps}
      className={cn('kyokuya-react-link', 'kyokuya-react-link--internal', className)}
      to={url}
      title={title}
    >
      {children}
    </Link>
  )
}

InternalLink.propTypes = linkPropTypes
InternalLink.displayName = 'KyokuyaInternalLink'
