import type { ILayoutComponentProps } from '@kyokuya/react-storage'
import { Theme } from '@yozora/core-react-theme'
import React from 'react'
import { SiteActionType, useSiteContext } from '@/core/context/site'
import { useLayoutPostContext } from './context'

export const LayoutPostLayoutComponent: React.FC<ILayoutComponentProps> = props => {
  return (
    <React.Fragment>
      <ListenThemeChanges />
      {props.children}
    </React.Fragment>
  )
}

const ListenThemeChanges: React.FC = () => {
  const { dispatch } = useSiteContext()
  const [darken] = useLayoutPostContext(({ state }) => [state.darken])

  React.useEffect(() => {
    dispatch({
      type: SiteActionType.PATCH_PREFERENCE,
      payload: { theme: darken ? Theme.DARKEN : Theme.LIGHT },
    })
  }, [darken, dispatch])

  return <React.Fragment />
}
