import BrightnessHighIcon from '@mui/icons-material/Brightness1'
import BrightnessLowIcon from '@mui/icons-material/Brightness2'
import Slider from '@mui/material/Slider'
import { withStyles } from '@mui/styles'
import cn from 'clsx'
import PropTypes from 'prop-types'
import React from 'react'
import { LayoutPostActionType, useLayoutPostContext } from '../context'

const CustomSlider = withStyles({
  root: {
    color: 'hsla(0deg, 0%, 80%, 0.75)',
    height: 8,
  },
})(Slider)

export const BrightnessSlider: React.FC<{ className?: string }> = ({ className }) => {
  const [hovering, setHovering] = React.useState<boolean>(false)
  const { state, dispatch } = useLayoutPostContext()

  const handleBrightnessChange = React.useCallback<(_event: any, value: number | number[]) => void>(
    (_e, nextValue: any) => {
      dispatch({
        type: LayoutPostActionType.TOGGLE_THEME_BRIGHTNESS,
        payload: nextValue,
      })
    },
    [dispatch],
  )

  const handleToggleThemeMode = React.useCallback<React.MouseEventHandler>(
    e => {
      e.stopPropagation()
      dispatch({ type: LayoutPostActionType.TOGGLE_THEME_MODE })
    },
    [dispatch],
  )

  const Icon = state.darken ? BrightnessLowIcon : BrightnessHighIcon
  return (
    <div
      className={cn(
        'kyokuya-post-brightness-slider',
        { 'kyokuya-post-brightness-slider--hovering': hovering },
        className,
      )}
      onMouseLeave={() => setHovering(false)}
    >
      <CustomSlider
        className={'kyokuya-post-brightness-slider__slider'}
        value={state.brightness}
        min={20}
        max={100}
        step={1}
        track="inverted"
        onChange={handleBrightnessChange}
        aria-label="change brightness"
      />
      <Icon
        className="kyokuya-post-brightness-slider__icon"
        onMouseEnter={() => setHovering(true)}
        onClick={handleToggleThemeMode}
      />
    </div>
  )
}

BrightnessSlider.propTypes = {
  className: PropTypes.string,
}

BrightnessSlider.displayName = 'KyokuyaLayoutPostBrightnessSlider'
export default BrightnessSlider
