import debounce from '@kyokuya/_shared/util/debounce'
import Link from '@kyokuya/react-link'
import CancelIcon from '@mui/icons-material/ClearOutlined'
import SearchIcon from '@mui/icons-material/SearchOutlined'
import { IconButton, Input, Switch } from '@mui/material'
import { withStyles } from '@mui/styles'
import cn from 'clsx'
import Fuse from 'fuse.js'
import PropTypes from 'prop-types'
import React from 'react'
import type { IPostItem } from '../context'
import { LayoutPostActionType, useLayoutPostContext } from '../context'

const TagListSwitch = withStyles({
  switchBase: {
    color: '#f6e1cc',
    '&$checked': {
      color: '#eda090',
    },
    '&$checked + $track': {
      backgroundColor: '#eda090',
    },
  },
  checked: {},
  track: {},
})(Switch)

export interface SearchPanelProps {
  /**
   * CSS class name
   */
  className?: string
}

// Search result item.
export type SearchResultItem = Fuse.FuseResult<IPostItem>

export const SearchPanel: React.FC<SearchPanelProps> = props => {
  const { state, dispatch } = useLayoutPostContext()
  const { searchingKeyword, searchingTagsVisible, tags, posts } = state
  const searchingKeywordRef = React.useRef<string>('')

  const [keyword, setKeyword] = React.useState<string>(searchingKeyword)
  const [searchingResult, setSearchingResult] = React.useState<ReadonlyArray<SearchResultItem>>([])

  const { search, handleKeywordChange, toggleTags } = React.useMemo(() => {
    const fullItems: SearchResultItem[] = posts.map((item, index) => ({
      item,
      matches: [],
      score: 1,
      refIndex: index,
    }))

    const titleSearcher = new Fuse<IPostItem>(posts, {
      includeScore: true,
      findAllMatches: true,
      threshold: 0.4,
      keys: ['title', 'tags'],
    })

    const tagSearcher = new Fuse<IPostItem>(posts, {
      includeScore: true,
      threshold: 0.4,
      keys: ['tags'],
    })

    const _search = (keyword: string): ReadonlyArray<SearchResultItem> => {
      if (keyword.length <= 0) return fullItems
      if (keyword[0] === '#') {
        if (keyword.length <= 0) return fullItems
        return tagSearcher.search(keyword.slice(1))
      }
      return titleSearcher.search(keyword)
    }

    const search = (keyword: string): void => {
      const resolvedKeyword = keyword.trim()
      if (searchingKeywordRef.current === resolvedKeyword) return

      searchingKeywordRef.current = resolvedKeyword
      const result = _search(keyword)
      setSearchingResult(result)
    }

    const syncKeyword = debounce(
      (keyword: string): void =>
        dispatch({
          type: LayoutPostActionType.SEARCH_REQUEST,
          payload: { keyword },
        }),
      200,
    )

    const handleKeywordChange = (keyword: string): void => {
      setKeyword(keyword)
      syncKeyword(keyword)
    }

    const toggleTags = (): void => dispatch({ type: LayoutPostActionType.TOGGLE_SEARCHING_TAGS })

    setSearchingResult(fullItems)
    return { search, handleKeywordChange, toggleTags }
  }, [posts, dispatch])

  React.useEffect(() => search(searchingKeyword), [searchingKeyword, search])

  const { className } = props
  return (
    <div className={cn('kyokuya-post-search-panel', className)}>
      <Input
        className="kyokuya-post-search-panel__input"
        type="input"
        value={keyword}
        placeholder="Searching post..."
        autoFocus={true}
        onChange={e => handleKeywordChange(e.target.value)}
        endAdornment={
          <React.Fragment>
            <SearchIcon className={cn({ hidden: keyword.length > 0 })} />
            <IconButton
              className={cn({ hidden: keyword.length <= 0 })}
              onClick={() => handleKeywordChange('')}
            >
              <CancelIcon />
            </IconButton>
          </React.Fragment>
        }
      />
      <div className="kyokuya-post-search-panel__main">
        <div className="kyokuya-post-search-panel__tags-switch">
          <span onClick={toggleTags}>tags</span>
          <TagListSwitch checked={searchingTagsVisible} onChange={toggleTags} />
        </div>
        <div
          className={cn('kyokuya-post-search-panel__tags', {
            hidden: !searchingTagsVisible,
          })}
        >
          {tags.map(tag => (
            <span
              key={tag}
              className="kyokuya-post-search-panel__tag"
              onClick={e => {
                e.stopPropagation()
                handleKeywordChange('#' + tag)
              }}
            >
              {tag}
            </span>
          ))}
        </div>
        <ul className="kyokuya-post-search-panel__results">
          {searchingResult.map(({ item }) => (
            <li key={item.title} className="kyokuya-post-search-panel__result-item">
              <Link
                className="kyokuya-post-search-panel__result-item-header"
                url={item.fields.slug}
                itemProp="url"
              >
                {item.title}
              </Link>
              <div className="kyokuya-post-search-panel__result-item-content">
                <span key="__date" className="kyokuya-post-search-panel__result-item-date">
                  {item.createAt}
                </span>
                🔖&nbsp;
                {item.tags.map(tag => (
                  <span
                    key={tag}
                    className="kyokuya-post-search-panel__result-item-tag"
                    onClick={() => handleKeywordChange('#' + tag)}
                  >
                    #{tag}
                  </span>
                ))}
              </div>
            </li>
          ))}
        </ul>
      </div>
    </div>
  )
}

SearchPanel.propTypes = {
  className: PropTypes.string,
}

SearchPanel.displayName = 'KyokuyaLayoutPostSearchPanel'
export default SearchPanel
